1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
3	const BLOCK_SIZE = 3;
4	const BLOCK_PREMIUM = 60;
5	
6	type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };
7	type QuoteStep = { op: "quote"; items: Item[] };
8	type Step = QuoteStep;
9	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
10	
11	type ItemTypeSpec = { basePremium: number; isComponent: boolean };
12	
13	const ITEM_TYPES: Record<string, ItemTypeSpec> = {
14	  sword: { basePremium: 100, isComponent: false },
15	  amulet: { basePremium: 60, isComponent: false },
16	  staff: { basePremium: 80, isComponent: false },
17	  potion: { basePremium: 40, isComponent: false },
18	  rune: { basePremium: 25, isComponent: true },
19	  moonstone: { basePremium: 25, isComponent: true },
20	};
21	
22	const countByType = (items: Item[]): Map<string, number> => {
23	  const counts = new Map<string, number>();
24	  for (const item of items) {
25	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
26	  }
27	  return counts;
28	};
29	
30	const premiumForTypeCount = (type: string, count: number): number => {
31	  const spec = ITEM_TYPES[type];
32	  return spec.isComponent && count === BLOCK_SIZE
33	    ? BLOCK_PREMIUM
34	    : count * spec.basePremium;
35	};
36	
37	const basePremiumOf = (items: Item[]): number => {
38	  let total = 0;
39	  for (const [type, count] of countByType(items)) {
40	    total += premiumForTypeCount(type, count);
41	  }
42	  return total;
43	};
44	
45	const CURSE_SURCHARGE_RATE = 0.5;
46	
47	const itemSurchargesOf = (items: Item[]): number =>
48	  items.reduce((sum, item) => {
49	    const itemBase = ITEM_TYPES[item.type].basePremium;
50	    const curse = item.cursed ? itemBase * CURSE_SURCHARGE_RATE : 0;
51	    return sum + curse;
52	  }, 0);
53	
54	const quoteForStep = ({ items }: QuoteStep) => {
55	  const basePremium = basePremiumOf(items);
56	  const itemSurcharges = itemSurchargesOf(items);
57	  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
58	  return { premium: Math.ceil(basePremium + itemSurcharges + firstInsuranceSurcharge + PROCESSING_FEE) };
59	};
60	
61	export const runScenario = (scenario: Scenario): unknown => {
62	  return { results: scenario.steps.map(quoteForStep) };
63	};
